-- name: ListSchedules :many
SELECT id, uid, date, attendance, time_valid, neutral_site, conference_competition, recent, start_date, notes_type, notes_headline, type_id, type_abbreviation, venue_id, venue_full_name, venue_address_city, venue_capacity, venue_indoor, status_clock, status_display_clock, status_period, status_type_id, status_type_name, status_type_state, status_type_completed, status_type_description, status_type_detail, status_type_short_detail, format_regulation_periods, home_id, home_uid, home_location, home_name, home_abbreviation, home_display_name, home_short_display_name, home_color, home_alternate_color, home_is_active, home_venue_id, home_logo, home_score, home_winner, away_id, away_uid, away_location, away_name, away_abbreviation, away_display_name, away_short_display_name, away_color, away_alternate_color, away_is_active, away_venue_id, away_logo, away_score, away_winner, game_id, season, season_type, venue_address_state, status_type_alt_detail, "PBP", team_box, player_box, game_date_time, game_date, play_by_play_available, broadcast, highlights, broadcast_market, broadcast_name, home_linescores, home_records, away_linescores, away_records, game_json, game_json_url FROM schedules
ORDER BY game_date DESC, game_id
LIMIT $1 OFFSET $2;
